module top_module(a, b, mode, clear, result);input [3:0] a;
  input [3:0] b;
  input [1:0] mode;
  input clear;
  output [3:0] result;

  reg [3:0] calc_result;

  always @ (a or b or mode or clear) begin
    case (mode)
      2'b00: calc_result = a + b;
      2'b01: calc_result = a - b;
      2'b10: calc_result = a * b;
      2'b11: calc_result = a / b;
    endcase

    if (clear) begin
      calc_result = 4'd0;
    end
  end

  assign result = calc_result;

endmodule
